commands.examples:
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  email TEXT NOT NULL
);

-- Composite primary key
CREATE TABLE enrollments (
  student_id INT,
  course_id INT,
  PRIMARY KEY (student_id, course_id)
);

CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  user_id INT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  product_id INT REFERENCES products(id) ON DELETE SET NULL
);

-- Deferrable FK
ALTER TABLE orders ADD CONSTRAINT fk_user
  FOREIGN KEY (user_id) REFERENCES users(id)
  DEFERRABLE INITIALLY DEFERRED;

CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  email TEXT UNIQUE NOT NULL,
  phone TEXT UNIQUE
);

-- Multi-column unique
ALTER TABLE permissions ADD CONSTRAINT uniq_user_role UNIQUE (user_id, role_id);

CREATE TABLE products (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  price DECIMAL CHECK (price >= 0),
  stock INT CHECK (stock >= 0),
  CONSTRAINT price_stock CHECK (price > 0 OR stock = 0)
);

CREATE TABLE events (
  start_date DATE NOT NULL,
  end_date DATE NOT NULL,
  CHECK (end_date >= start_date)
);

CREATE EXTENSION IF NOT EXISTS btree_gist;

CREATE TABLE reservations (
  room_id INT,
  during TSTZRANGE,
  EXCLUDE USING GIST (room_id WITH =, during WITH &&)
);

-- Tidak bisa booking room yang sama di waktu yang overlap
INSERT INTO reservations VALUES (1, '[2024-01-01, 2024-01-05)');
